"""
Christ Layer — 2 Chronicles chapters 29–31
Run: python3 scripts/zc-christ-2chronicles-29-31.py

Key typological connections:
- Ch 29: Hezekiah as new David opening the temple → Christ opening the way into
  the heavenly sanctuary (Heb 10:20); cleansing of inner sanctuary → Heb 9:23-24;
  sin offering for all Israel (v24) → Heb 9:26; sacrifice + song simultaneous (v27) → Rev 5:9;
  temple doors opened in first month/first year = new creation of worship
- Ch 30: Hezekiah's inclusive Passover — letters to all Israel and Ephraim;
  lēḇāḇ ʾeḥāḏ (one heart, v12) → Ezek 11:19/Acts 4:32; "whoever has set his heart
  to seek God" (v19) → faith beyond ritual purity; priestly blessing ascends to
  heaven (v27) → Heb 7:25 intercession of Christ
- Ch 31: Comprehensive reform; tithe abundance (v10 Azariah) → 2 Cor 9:6-8;
  Hezekiah's whole-heart summary (v20-21) → Matt 3:15 fulfilling all righteousness
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2_CHRIST_29_31 = {
  "29": {
    "1": "<p>Hezekiah begins his reign at age 25 — the same age as the Levites who entered service (Num 8:24), a detail the Chronicler presumably found significant. His reign of 29 years spans the Assyrian crisis and the restoration of worship. His mother&rsquo;s name Abijah (&ldquo;my father is YHWH&rdquo;) signals a maternal heritage of covenant naming. Hezekiah is the Chronicler&rsquo;s second-greatest king (after Josiah), the exemplar of reform and restoration whose program typifies what the true Davidic heir will accomplish definitively.</p>",
    "2": "<p>&ldquo;He did what was right in the sight of the LORD, just as his ancestor David had done.&rdquo; The David-standard is the Chronicler&rsquo;s highest positive evaluation; only Hezekiah and Josiah receive this unqualified comparison. To be like David is to be the closest approximation of the ideal king the dynasty has produced. Christ receives this accolade at the divine level: he is not compared to David but called David&rsquo;s son and lord simultaneously (Matt 22:42-45), the one of whom David himself is a type rather than a standard.</p>",
    "3": "<p>&ldquo;In the first year of his reign, in the first month, he opened the doors of the LORD&rsquo;s house.&rdquo; The first-month/first-year dating echoes Exod 40:17, when the tabernacle was erected on the first day of the first month — a new creation of worship. Hezekiah&rsquo;s first act is to reopen what Ahaz had closed; the opening of the temple doors is the opening of access to YHWH. Christ opens a &ldquo;new and living way through the curtain&rdquo; (Heb 10:20) — not merely reopening a door Ahaz closed but opening access to the Father that no fallen king or closed door had ever provided.</p>",
    "4": "<p>Hezekiah assembles the priests and Levites in the open square on the east side — the gathering before the formal consecration begins. The public assembly of temple personnel is the first step of the reform: the reform of worship requires the reform of the worshipers. Christ similarly consecrates his people before they can serve: &ldquo;For them I consecrate myself, that they too may be truly consecrated&rdquo; (John 17:19); the consecration of the ministers follows from the consecration of the high priest.</p>",
    "5": "<p>&ldquo;Consecrate yourselves now, and consecrate the house of the LORD.&rdquo; The double consecration — of persons and of the sanctuary — reflects the biblical logic that the place of worship cannot be holy if those who serve there are unholy. Christ enacts both: he is himself the holy one (Luke 1:35; John 17:11) who consecrates his people (1 Cor 1:2: &ldquo;sanctified in Christ Jesus&rdquo;) and who is himself the holy sanctuary they approach (Heb 10:19-22).</p>",
    "6": "<p>Hezekiah&rsquo;s confession: &ldquo;Our fathers were unfaithful (<em>māʿălû</em>) and did what was evil... they forsook him, turned their faces away from the LORD&rsquo;s tabernacle, and turned their backs.&rdquo; The corporate confession of ancestral sin — <em>māʿal</em> (the Chronicler&rsquo;s key word for covenant treachery) applied to the previous generation — opens the way for the new king&rsquo;s reform. Christ inherits the full weight of the corporate sin of his people and addresses it not by confession but by substitution: &ldquo;God made him who had no sin to be sin for us&rdquo; (2 Cor 5:21).</p>",
    "7": "<p>Three specific acts of apostasy under Ahaz: shutting the vestibule doors, extinguishing the lamps, ceasing incense and burnt offerings. Each act extinguishes a layer of divine-human communication — the lamps represent YHWH&rsquo;s visible presence (the menorah, Exod 25:31-40), incense represents prayer (Ps 141:2; Rev 5:8; 8:3-4), and burnt offerings represent the daily covenant maintenance. Ahaz did not merely neglect worship; he systematically shut down every channel of communication with YHWH. Christ reopens all three: he is the light of the world (John 8:12), his intercession is the ascending incense (Heb 7:25), and his sacrifice is the ultimate burnt offering (Heb 10:10).</p>",
    "8": "<p>&ldquo;Therefore the LORD&rsquo;s wrath fell on Judah and Jerusalem&rdquo; — the divine-human causation is explicit. The Chronicler never hides the connection between apostasy and judgment; the wrath is not arbitrary but covenantally structured. Hezekiah speaks of this wrath to the priests and Levites so they understand the gravity of the reform: they are not performing a liturgical renovation but undoing a judgment. Christ addresses the wrath from the other direction: he bears it in his body (1 Pet 2:24) so his people are released from it (1 Thess 1:10: &ldquo;Jesus, who rescues us from the coming wrath&rdquo;).</p>",
    "9": "<p>&ldquo;Behold, our fathers have fallen by the sword, and our sons and daughters and wives are in captivity because of this.&rdquo; The specific costs of apostasy: death in battle and exile for dependents. Hezekiah presents the concrete human consequences of his predecessors&rsquo; failure to motivate the priests. The good news of the gospel addresses exactly these costs: the sword of divine judgment falls on Christ (Zech 13:7: &ldquo;Awake, sword, against my shepherd&rdquo;; Matt 26:31) so his people are not struck; the captivity is released by the one who proclaims &ldquo;freedom for the prisoners&rdquo; (Luke 4:18).</p>",
    "10": "<p>&ldquo;Now I intend to make a covenant (<em>liqrāṯ bᵉrîṯ</em>) with the LORD, the God of Israel, so that his fierce anger may turn away from us.&rdquo; Hezekiah as covenant initiator — the king who proposes covenant renewal as the solution to divine wrath. The pattern follows 2 Chr 15:12 (Asa), 23:16 (Jehoiada), and anticipates Josiah (34:31). Christ is not merely a covenant initiator but the mediator of &ldquo;a better covenant established on better promises&rdquo; (Heb 8:6), the one who turns away wrath not by proposing a covenant but by being its sacrifice (Heb 9:15).</p>",
    "11": "<p>&ldquo;My sons, do not be negligent now, for the LORD has chosen you to stand before him, to minister to him, and to be his ministers and to burn incense.&rdquo; The language of divine election for priestly service — &ldquo;chosen you to stand before him&rdquo; — is the basis of both Levitical ministry and the NT priesthood of all believers. Christ is the one who stands before the Father as the permanent mediator (Heb 9:24: &ldquo;he entered heaven itself, now to appear for us in God&rsquo;s presence&rdquo;) and who calls his people to the same standing: &ldquo;you are a chosen people, a royal priesthood&rdquo; (1 Pet 2:9).</p>",
    "12": "<p>The Levites who respond to Hezekiah&rsquo;s call are named — fourteen named individuals from four Levitical families (Kohathites, Merarites). The Chronicler&rsquo;s care with names reflects his conviction that individuals matter in the covenant community; the reform is carried out by specific named people, not anonymous functionaries. Christ calls his disciples by name (John 10:3: &ldquo;he calls his own sheep by name&rdquo;) and the NT repeatedly names those who responded to the gospel call.</p>",
    "13": "<p>Shimri, Jeiel, Zechariah, Mattaniah from the sons of Elizaphan and Asaph — the musical Levites are included in the reform workforce. The Asaphites were the singers established by David; their inclusion signals that the musical dimension of worship is being restored alongside the sacrificial. The integration of song into the reform team reflects the Chronicler&rsquo;s conviction that praise is not an optional addition to worship but intrinsic to it.</p>",
    "14": "<p>Jehiel, Shimei, Shemaiah, Uzziel from the sons of Heman and Jeduthun — the three great Davidic guilds of musicians (Asaph, Heman, Jeduthun) all represented. The three guilds together provide a complete musical worship leadership. In Revelation, the worship of heaven is led by the four living creatures and the twenty-four elders who hold harps and bowls of incense (Rev 5:8) — the heavenly liturgy that the three Davidic guilds prefigure.</p>",
    "15": "<p>&ldquo;They gathered their fellow Levites, consecrated themselves, and went in — as the king commanded, by the word of the LORD — to cleanse the LORD&rsquo;s house.&rdquo; The double authority structure: the king&rsquo;s command = the LORD&rsquo;s word. Hezekiah&rsquo;s commands are transparently YHWH&rsquo;s commands — the ideal king-prophet alignment. Jesus operates by the same principle at a deeper level: &ldquo;the words I say to you I do not speak on my own authority. Rather, it is the Father, living in me, who is doing his work&rdquo; (John 14:10).</p>",
    "16": "<p>The priests enter the inner sanctuary to cleanse it, bringing out all the uncleanness to the Kidron Valley. The defilement must be physically removed from the sacred space — taken out of the holy precinct to the waste disposal valley. The author of Hebrews uses this imagery theologically: &ldquo;It was necessary, then, for the copies of the heavenly things to be purified with these sacrifices, but the heavenly things themselves with better sacrifices than these&rdquo; (Heb 9:23). The Kidron Valley cleansing is the earthly type of the purification of the heavenly sanctuary that Christ&rsquo;s blood accomplishes.</p>",
    "17": "<p>The consecration begins on the first day of the first month; by the eighth day they reach the vestibule, and by the sixteenth they finish. The sixteen-day process of cleansing places the completion in the week of Passover-Unleavened Bread (Nisan 14-21). The temple is cleansed just as the Passover calendar arrives — the theological timing is not accidental in the Chronicler&rsquo;s account: the purified sanctuary is ready for the covenant&rsquo;s founding feast. Christ is crucified at Passover on a day when the temple he had recently cleansed (John 2:14-17) receives his sacrifice.</p>",
    "18": "<p>The Levites report to the king: &ldquo;We have purified the entire house of the LORD, including the altar of burnt offering and all its vessels.&rdquo; The completion report is a priestly declaration of readiness. Christ makes a similar declaration from the cross: &ldquo;It is finished&rdquo; (John 19:30; <em>tetelestai</em>) — the completed work of purification that opens access to the Father. The Levites&rsquo; completion report prepares for the sacrifice of ch 29:20-36; Christ&rsquo;s &ldquo;finished&rdquo; is the sacrifice itself.</p>",
    "19": "<p>&ldquo;All the vessels that King Ahaz set aside during his unfaithful reign we have prepared and consecrated — they are now before the altar of the LORD.&rdquo; The vessels desecrated by Ahaz are reconsecrated — defilement is not permanent when the priestly work of purification is done. This is the pattern of redemption: what was defiled by sin is reconsecrated by the blood of Christ; &ldquo;the blood of Jesus his Son purifies us from all sin&rdquo; (1 John 1:7). No vessel is beyond reconsecration if the high priest applies the blood.</p>",
    "20": "<p>&ldquo;King Hezekiah rose early (<em>wayyaškem</em>), gathered the city&rsquo;s officials, and went up to the LORD&rsquo;s house.&rdquo; The verb <em>šāḵam</em> (rise early) is the vocabulary of covenant urgency — it appears in Jer 7:13, 25 as &ldquo;rising early and speaking&rdquo; to describe YHWH&rsquo;s persistent prophetic sending. Jesus also rises early for prayer (Mark 1:35) and the resurrection is discovered &ldquo;very early in the morning&rdquo; (Mark 16:2). Rising early signals that worship is the first priority — before other business, before comfort.</p>",
    "21": "<p>Seven bulls, seven rams, seven lambs, seven goats for the sin offering — the quadruple seven signals completeness and totality; this is the fullest possible sin offering before the law could provide. The offering is &ldquo;for the kingdom, for the sanctuary, and for Judah&rdquo; — three concentric circles of scope. Christ&rsquo;s one offering for sin is greater: &ldquo;not for his own sins only but also for the sins of the whole world&rdquo; (1 John 2:2), the ultimate expansion beyond Hezekiah&rsquo;s three circles to encompass creation itself.</p>",
    "22": "<p>The priests receive the blood and sprinkle it on the altar — bulls, rams, lambs each in sequence. The blood ritual is the heart of the atonement system; without blood there is no forgiveness (Heb 9:22). The repetition of the sprinkling for each category of animal reflects the thoroughness of the atoning act. Christ&rsquo;s blood is sprinkled once — but the author of Hebrews draws on the same blood-sprinkling language: &ldquo;to Jesus the mediator of a new covenant, and to the sprinkled blood that speaks a better word than the blood of Abel&rdquo; (Heb 12:24).</p>",
    "23": "<p>&ldquo;The male goats for the sin offering were brought before the king and the assembly, who laid their hands on them.&rdquo; The hand-laying (<em>sāmaḵ</em>) identifies the worshiper with the sacrifice — the animal bears what the worshiper deserves. This is the substitutionary logic made visible: hands on the animal&rsquo;s head transfers the sin. The NT identifies Christ as the one on whom YHWH laid the iniquity of all: &ldquo;the LORD has laid on him the iniquity of us all&rdquo; (Isa 53:6); &ldquo;God made him who had no sin to be sin for us&rdquo; (2 Cor 5:21).</p>",
    "24": "<p>&ldquo;The priests slaughtered them and made a sin offering with their blood on the altar to atone for all Israel. For the king commanded that the burnt offering and the sin offering be made for all Israel.&rdquo; The explicit scope — &ldquo;all Israel&rdquo; — is the broadest possible within the Mosaic system; Hezekiah reaches beyond the present gathering to the entire covenant people including the exiled northern tribes. Christ&rsquo;s atonement explicitly reaches beyond any national or ethnic boundary: &ldquo;he is the atoning sacrifice for our sins, and not only for ours but also for the sins of the whole world&rdquo; (1 John 2:2); &ldquo;by one sacrifice he has made perfect forever those who are being made holy&rdquo; (Heb 10:14).</p>",
    "25": "<p>Hezekiah stations the Levites in the temple with cymbals, harps, and lyres &ldquo;as commanded by David, by Gad the king&rsquo;s seer, and by Nathan the prophet.&rdquo; Three authorities — David, Gad, Nathan — validate the musical order; the Levitical music has divine prophetic authorization, not merely royal preference. In Revelation, the worship of heaven is similarly structured: the twenty-four elders hold harps (Rev 5:8) and the redeemed sing the new song (Rev 14:2-3) — the Davidic guilds&rsquo; worship is the earthly version of the heavenly liturgy that never ceases.</p>",
    "26": "<p>Levites with David&rsquo;s instruments, priests with trumpets — the complementary roles of the two orders in worship. The Chronicler&rsquo;s consistent emphasis on the complementarity of priestly and Levitical function points toward the NT&rsquo;s vision of the body of Christ: &ldquo;Just as each of us has one body with many members, and these members do not all have the same function, so in Christ we, though many, form one body, and each member belongs to all the others&rdquo; (Rom 12:4-5). The musical worship of the Hezekian temple displays the unified-yet-diverse community of the covenant.</p>",
    "27": "<p>&ldquo;At the moment the burnt offering began, the song to the LORD began, and the trumpets sounded, accompanied by the instruments of David king of Israel.&rdquo; The precise simultaneity — sacrifice and song start at the same moment — is the Chronicler&rsquo;s theological statement: true worship integrates offering and praise; neither precedes the other. In Revelation, the Lamb who is &ldquo;like a lamb that was slain&rdquo; (Rev 5:6) is immediately the object of the new song (Rev 5:9): the sacrifice and the song are simultaneous in the heavenly liturgy. The cross and the doxology occur together.</p>",
    "28": "<p>The whole congregation bowed in worship while the singers sang and the trumpeters sounded, &ldquo;continuing until the burnt offering was complete.&rdquo; Corporate worship sustained throughout the sacrifice — the assembly does not merely attend but actively participates in posture (bowing) and attention (waiting until completion). The NT equivalent is the Lord&rsquo;s Supper, which is explicitly a remembrance &ldquo;until he comes&rdquo; (1 Cor 11:26) — a sustained act of worship that looks backward to the sacrifice and forward to the completion.</p>",
    "29": "<p>&ldquo;When the offering was finished, the king and everyone with him bowed and worshipped.&rdquo; The completed offering produces worship — the sequence of sacrifice completed → assembly bowing is the structure of the NT response to the cross: &ldquo;Therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow&rdquo; (Phil 2:9-10). The kneeling of the Hezekian assembly after the completion of the sacrifice is the type of the universal kneeling that the completion of Christ&rsquo;s sacrifice will produce.</p>",
    "30": "<p>King Hezekiah and the officials command the Levites to sing praise &ldquo;in the words of David and of Asaph the seer.&rdquo; The Psalms become the liturgical vocabulary of the restored worship; David&rsquo;s words and Asaph&rsquo;s are the authorized language for approaching YHWH. Christ himself prays the Psalms from the cross (Ps 22:1 in Matt 27:46; Ps 31:5 in Luke 23:46), so the recovery of Davidic psalm-prayer that Hezekiah commands is the recovery of the prayer vocabulary that the Son of David will bring to its deepest expression in his passion.</p>",
    "31": "<p>&ldquo;Now that you have consecrated yourselves to the LORD, come and bring your sacrifices and thank offerings to the LORD&rsquo;s house.&rdquo; Hezekiah&rsquo;s invitation follows consecration — you are now qualified to bring your offerings. The sequence (consecration first, then offering) is the gospel pattern: Christ consecrates his people (Heb 10:10: &ldquo;we have been made holy through the sacrifice of the body of Jesus Christ once for all&rdquo;) and then invites them to offer spiritual sacrifices: &ldquo;offer your bodies as a living sacrifice, holy and pleasing to God&rdquo; (Rom 12:1).</p>",
    "32": "<p>The congregation&rsquo;s burnt offerings: 70 bulls, 100 rams, 200 lambs — vast numbers reflecting the assembly&rsquo;s grateful response to the renewed covenant. The people&rsquo;s giving exceeds the king&rsquo;s initiating sacrifice (vv21-24). This is the pattern of grace producing generosity: once the covenant is renewed by royal initiative, the people give abundantly. The same dynamic appears in Acts 2-4: once the apostolic proclamation establishes the new covenant community, the believers give generously and voluntarily (Acts 2:44-45; 4:32-35).</p>",
    "33": "<p>Consecrated offerings: 600 oxen, 3,000 sheep — the peace/fellowship offerings separate from the burnt offerings. The scale of the offering (hundreds of animals) reflects the depth of the covenant renewal; the whole community participates in the sacrifice, not just the king. The participatory character of Hezekiah&rsquo;s offerings anticipates the NT&rsquo;s vision of the whole community as priests offering acceptable sacrifices: &ldquo;offer spiritual sacrifices acceptable to God through Jesus Christ&rdquo; (1 Pet 2:5).</p>",
    "34": "<p>Not enough priests to skin all the burnt offerings — the Levites help until the work was finished and more priests consecrated themselves. The reform produces more worship than the existing infrastructure can handle; the supply of priestly service cannot keep up with the congregation&rsquo;s response. The Chronicler notes this as a positive problem, evidence of genuine revival. The NT equivalent: the early church grew faster than its existing leadership structures could support (Acts 6:1-7: &ldquo;the disciples were increasing in number&rdquo;; the appointment of the seven to handle the logistical overflow).</p>",
    "35": "<p>The burnt offerings were plentiful, along with the fat of the fellowship offerings and the drink offerings for each burnt offering — the full liturgical system fully engaged. All three major offering types (burnt, fellowship, drink) are flowing simultaneously; the entire sacrificial system is operational for the first time since Ahaz. The richness of the sacrificial calendar under Hezekiah is the type of the richness of Christ&rsquo;s one offering that encompasses all categories: he is at once the burnt offering (complete consecration), the peace offering (fellowship restored), and the drink offering (poured out entirely, 2 Tim 4:6).</p>",
    "36": "<p>&ldquo;Hezekiah and all the people rejoiced over what God had prepared (<em>hēkîn</em>) for the people, for it had all happened so quickly.&rdquo; The divine preparation (<em>kûn</em>) and the surprising speed are both emphasized. YHWH prepared the conditions for the revival; the people&rsquo;s response exceeded all expectations in both scale and speed. The divine preparation underlying all human response to grace is the structure of salvation: &ldquo;it is God who works in you to will and to act in order to fulfill his good purpose&rdquo; (Phil 2:13). The joy of the Hezekian assembly is the joy of a community that has discovered it was prepared for by God before it prepared for God.</p>"
  },
  "30": {
    "1": "<p>Hezekiah sends invitations to &ldquo;all Israel and Judah&rdquo; including Ephraim and Manasseh — crossing the political border that has divided the kingdom since Rehoboam. The letter-form of the invitation (v6) is the first royal use of writing for gospel-proclamation in Chronicles; the king writes to summon the scattered covenant people. The pattern anticipates Paul&rsquo;s letters that constitute the NT&rsquo;s invitation-to-gather — the proclamation that goes out to the dispersed before the assembly convenes.</p>",
    "2": "<p>The Passover is moved to the second month — a concession enabled by Num 9:10-11 (the provision for a &ldquo;second Passover&rdquo; for those ritually impure or on a journey). Hezekiah applies a legal provision creatively to enable maximum participation. The spirit over the letter — the purpose of the Passover (covenant renewal through the memorial feast) is served by the delay. Jesus makes the same hermeneutical move: &ldquo;the Sabbath was made for man, not man for the Sabbath&rdquo; (Mark 2:27); the law&rsquo;s provisions serve covenant life, not the reverse.</p>",
    "3": "<p>The delay is necessary because not enough priests have consecrated themselves and the people have not gathered in Jerusalem. The practical barrier to worship — unpreparedness — is addressed by the legal provision of a second-month Passover. The Chronicler presents this not as compromise but as wise application of Torah; the letter of the law enables the spirit of the feast. Christ similarly enables participation in the feast that was previously impossible: the unclean who could not approach can now come through his cleansing (Heb 10:22).</p>",
    "4": "<p>The plan seems right to the king and the whole assembly — communal discernment validates the decision. The Chronicler often notes that significant decisions receive the consent of the whole congregation (cf. 1 Chr 13:2; 29:20); covenant decisions are not made unilaterally by kings but ratified by the community. The early church follows the same pattern: &ldquo;it seemed good to the Holy Spirit and to us&rdquo; (Acts 15:28) — communal discernment including divine and human approval.</p>",
    "5": "<p>&ldquo;From Beersheba to Dan&rdquo; — the full extent of united Israel, the phrase used for the undivided kingdom under Samuel (1 Sam 3:20) and David (2 Sam 17:11). Hezekiah&rsquo;s proclamation imagines and attempts the reconstitution of the undivided kingdom through the feast. The eschatological gathering that the Passover invitation anticipates is the gathering of all Israel under the one shepherd: &ldquo;there will be one flock and one shepherd&rdquo; (John 10:16); &ldquo;the scattered children of God, to bring them together and make them one&rdquo; (John 11:52).</p>",
    "6": "<p>The royal couriers carry the king&rsquo;s letter throughout all Israel and Judah with this invitation: &ldquo;Return to the LORD, the God of Abraham, Isaac, and Israel.&rdquo; The covenantal address — invoking the patriarchal names of the Abrahamic covenant — grounds the invitation in the original promise. The proclamation to return (<em>šûḇ</em>) is the prophetic vocabulary of repentance (Isa 31:6; Jer 4:1; Hos 6:1; Mal 3:7). Christ makes the same appeal: &ldquo;Come to me, all who are weary and burdened&rdquo; (Matt 11:28) — the invitation language of return, rest, and relationship.</p>",
    "7": "<p>&ldquo;Do not be like your fathers and brothers, who were unfaithful (<em>māʿălû</em>) to the LORD... so that he made them a desolation, as you can see.&rdquo; The visible desolation of the northern kingdom is the evidence that YHWH means what he says about covenant faithfulness. The warning uses the history of failure as a motivation for the invitation&rsquo;s recipients. Paul uses the same rhetorical structure: &ldquo;these things happened to them as examples and were written down as warnings for us&rdquo; (1 Cor 10:11) — the catastrophes of Israel&rsquo;s history are teaching material for those who receive the gospel invitation.</p>",
    "8": "<p>&ldquo;Do not be stiff-necked (<em>ʾal-taqšû ʿorpᵉḵem</em>) like your ancestors, but submit (<em>tᵉnû yāḏ</em>, give the hand = yield) to the LORD. Come to his sanctuary which he has consecrated forever.&rdquo; Three imperatives in sequence: don&rsquo;t be stiff-necked, submit, come. The sanctuary is &ldquo;consecrated forever&rdquo; (<em>lᵉʿôlām</em>) — its holiness is permanent even when Israel has abandoned it. Christ&rsquo;s consecration of the heavenly sanctuary is equally permanent: &ldquo;he entered heaven itself, now to appear for us in God&rsquo;s presence&rdquo; (Heb 9:24) — the sanctuary that never needs recleaning because the sacrifice never needs repeating.</p>",
    "9": "<p>&ldquo;For if you return to the LORD, your brothers and children will find compassion from their captors and come back to this land, for the LORD your God is gracious and compassionate (<em>ḥannûn wᵉraḥûm</em>).&rdquo; The proclamation of divine character — gracious and compassionate — is the theological center of the gospel invitation. The two attributes (<em>ḥannûn wᵉraḥûm</em>) are the core of YHWH&rsquo;s self-disclosure in Exod 34:6. The promise that returning produces the return of captives from exile is the structure of spiritual restoration: repentance produces the reconciliation of all that was broken. Christ announces the same: &ldquo;repent, for the kingdom of heaven has come near&rdquo; (Matt 4:17) — and the kingdom&rsquo;s arrival restores what sin scattered.</p>",
    "10": "<p>The couriers travel through Ephraim and Manasseh to Zebulun — but the people &ldquo;laughed and mocked them.&rdquo; The mockers reject the invitation; the warning of v7 has not moved them. The divided response to gospel proclamation is the NT&rsquo;s consistent experience: &ldquo;some of them were persuaded and joined Paul and Silas, as did a large number of God-fearing Greeks... but the Jews were jealous&rdquo; (Acts 17:4-5). Jesus narrates this structure in the parable of the great banquet: &ldquo;they all alike began to make excuses&rdquo; (Luke 14:18); the invited mock or ignore the invitation.</p>",
    "11": "<p>&ldquo;Nevertheless, some men from Asher, Manasseh, and Zebulun humbled themselves and came to Jerusalem.&rdquo; The faithful remnant from the north — tribes that mocked Hezekiah&rsquo;s invitation also contained those who responded. The word &ldquo;nevertheless&rdquo; (<em>ʾăḵēn</em>) is the hinge between the mockers and the humble; it introduces grace as the surprise after rejection. Jesus says: &ldquo;small is the gate and narrow the road that leads to life, and only a few find it&rdquo; (Matt 7:14); &ldquo;many are invited, but few are chosen&rdquo; (Matt 22:14). The few who come from the north are the type of the faithful remnant that grace always produces.</p>",
    "12": "<p>&ldquo;Also in Judah God&rsquo;s hand gave them one heart (<em>lēḇ ʾeḥāḏ</em>) to carry out the command of the king and the officials, as the word of the LORD commanded.&rdquo; The &ldquo;one heart&rdquo; is divinely given — the unity of the Passover assembly is not human consensus but divine work. This is the Chronicler&rsquo;s most explicit statement of the new covenant&rsquo;s reality before it is formally announced: Ezek 11:19 promises &ldquo;I will give them one heart and put a new spirit within them.&rdquo; The one-heart community at Hezekiah&rsquo;s Passover is the type of the Acts community: &ldquo;all the believers were one in heart and mind&rdquo; (Acts 4:32).</p>",
    "13": "<p>A very great assembly gathers in Jerusalem for the second-month Festival of Unleavened Bread — numerically significant and geographically diverse. The great assembly (<em>qāhāl rāḇ mᵉʾōḏ</em>) that gathers around the Passover feast is the type of the eschatological assembly around the Lamb: &ldquo;a great multitude that no one could count, from every nation, tribe, people and language, standing before the throne and before the Lamb&rdquo; (Rev 7:9).</p>",
    "14": "<p>They tear down the pagan altars in Jerusalem and throw them into the Kidron Valley — the same valley where temple defilements had been dumped (29:16). The assembly purifies the city as well as the sanctuary; the reform extends from the temple outward. This is the same pattern as Jesus&rsquo; temple cleansing (John 2:15-17), which itself moves from the temple court outward — the purification of the holy center produces purification of the surrounding space.</p>",
    "15": "<p>The Passover lamb is slaughtered on the 14th of the second month. The priests and Levites are &ldquo;ashamed&rdquo; and consecrate themselves — the assembly&rsquo;s zeal has provoked the temple professionals to repentance. The reversal is significant: lay people and northern visitors are leading in covenant faithfulness while the Levites feel convicted. Jesus describes a similar reversal: &ldquo;tax collectors and prostitutes are entering the kingdom of God ahead of you&rdquo; (Matt 21:31) — the expected leaders shamed by the unexpected respondents.</p>",
    "16": "<p>The priests and Levites take their prescribed positions; the Levites bring the blood from those who are not ritually clean. The system adjusts to serve the larger purpose: those who cannot participate fully receive the Levites&rsquo; service as mediators. The NT makes this accommodation permanent: Christ is the mediator for all who cannot approach by their own ritual purity — &ldquo;we have one who speaks to the Father in our defense&rdquo; (1 John 2:1).</p>",
    "17": "<p>Many in the congregation have not consecrated themselves, so the Levites slaughter the Passover lamb for all who are not ritually clean. The Levitical accommodation extends the Passover to the otherwise excluded — those who cannot participate by the normal standard are included by the Levites&rsquo; mediation. This is a structural anticipation of Christ&rsquo;s priestly work: he enables participation in the covenant feast for those who have no standing by normal standards.</p>",
    "18": "<p>A large number from Ephraim, Manasseh, Issachar, and Zebulun eat the Passover without being cleansed — technically violating Lev 7:20-21. Yet they eat. Hezekiah&rsquo;s response (v19) is to pray rather than exclude. The pastoral instinct to pray for the heart-seeking-but-ritually-unqualified is the proto-gospel move: the question shifts from &ldquo;does this person meet the ritual standard?&rdquo; to &ldquo;has this person set their heart on seeking God?&rdquo;</p>",
    "19": "<p>&ldquo;Whoever has set his heart (<em>hēkîn lᵉḇāḇô</em>) to seek God, the LORD, the God of his ancestors, even if he is not cleansed as the sanctuary requires.&rdquo; Hezekiah&rsquo;s prayer articulates the most significant pastoral-theological principle in Chronicles outside the Davidic covenant: the prepared heart oriented toward God is the sufficient condition for inclusion, even without ritual purity. This is the Chronicler&rsquo;s nearest approach to justification by faith. Christ makes it explicit: &ldquo;Blessed are the pure in heart, for they will see God&rdquo; (Matt 5:8) — the heart&rsquo;s orientation toward God, not ritual status, determines access.</p>",
    "20": "<p>&ldquo;And the LORD listened to Hezekiah and healed (<em>wayyirpāʾ</em>) the people.&rdquo; Divine healing in response to priestly intercession — the exact priestly function of intercession producing divine healing. Hezekiah&rsquo;s prayer for the ritually-unqualified is answered by divine healing that makes them acceptable. Christ&rsquo;s intercession accomplishes the same: &ldquo;he is able to save completely those who come to God through him, because he always lives to intercede for them&rdquo; (Heb 7:25). The healing word of YHWH in response to priestly prayer is the structure of salvation.</p>",
    "21": "<p>The Festival of Unleavened Bread celebrated for seven days with great joy — the Levites and priests praise YHWH daily with loud instruments. The &ldquo;loud instruments&rdquo; (<em>kᵉlê ʿōz</em>, instruments of strength) accompanying the daily praise reflect the intensity of worship. The seven-day continuous praise is the type of the eternal worship of Rev 4:8: &ldquo;day and night they never stop saying: Holy, holy, holy is the Lord God Almighty.&rdquo;</p>",
    "22": "<p>Hezekiah speaks encouragingly to all the Levites who showed skill and understanding in the LORD&rsquo;s service — pastoral acknowledgment of those who served well. The role of the leader who affirms and encourages his servants is the model for the good shepherd who knows his sheep (John 10:14) and for the master who says &ldquo;well done, good and faithful servant&rdquo; (Matt 25:21). The Passover feast includes seven days of fellowship offerings — the feast extends for the full week.</p>",
    "23": "<p>The whole assembly decides to celebrate for another seven days — spontaneous extension of the feast because the joy is too great to end. The community extends the festival by corporate decision: the seven days of the law become fourteen by the people&rsquo;s joy. This is the type of the eschatological feast that has no end — the wedding supper of the Lamb (Rev 19:9) is not a seven-day feast with a scheduled conclusion but the eternal celebration of the completed work of redemption.</p>",
    "24": "<p>Hezekiah contributes 1,000 bulls and 7,000 sheep; the officials contribute another 1,000 bulls and 10,000 sheep; many priests consecrate themselves. The royal and official generosity provides for the extended feast — the king gives from his resources so the people can celebrate. Christ gives himself so the wedding feast can be attended: &ldquo;for the wedding of the Lamb has come, and his bride has made herself ready&rdquo; (Rev 19:7) — the feast is provided by the one who invites.</p>",
    "25": "<p>The whole congregation of Judah rejoices — priests, Levites, all who came from Israel, the foreigners who came from Israel, and those living in Judah. The multi-ethnic character of the assembly — including foreigners (<em>gērîm</em>) alongside native Israelites — is the Chronicler&rsquo;s vision of the covenant community at its best. Paul articulates the NT fulfillment: &ldquo;there is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus&rdquo; (Gal 3:28).</p>",
    "26": "<p>&ldquo;There was great joy in Jerusalem, nothing like it since the time of Solomon son of David king of Israel.&rdquo; The Solomonic comparison marks this as the greatest outbreak of joy in the post-Solomonic era. Solomon&rsquo;s dedication joy (7:10) is the benchmark; Hezekiah&rsquo;s Passover joy reaches the same level. The pattern of joy escalation through Israel&rsquo;s history points to the joy that surpasses all previous joy: the resurrection joy that produces a new song no one had heard before (Rev 5:9; 14:3).</p>",
    "27": "<p>&ldquo;Then the priests and the Levites stood up to bless the people; and their voice was heard, and their prayer ascended to his holy dwelling in heaven.&rdquo; The priestly blessing (Num 6:24-26) reaches the divine throne directly — from the Jerusalem temple courts to &ldquo;his holy dwelling in heaven.&rdquo; The ascent of prayer to the heavenly sanctuary is the premise of all priestly intercession; Christ makes this access permanent and direct: he is himself in the heavenly sanctuary &ldquo;now to appear for us in God&rsquo;s presence&rdquo; (Heb 9:24), and through him &ldquo;we may approach God&rsquo;s throne of grace with confidence&rdquo; (Heb 4:16).</p>"
  },
  "31": {
    "1": "<p>When the festival ends, all Israelites present go out and smash the sacred pillars, cut down the Asherim, and demolish the high places and altars throughout Judah, Benjamin, Ephraim, and Manasseh. The Passover feast produces immediate reform: the encounter with YHWH at the feast generates the energy to remove what offends him. The same pattern occurs at Pentecost: the disciples who receive the Spirit at the feast immediately begin the transformation of Jerusalem (Acts 2:41-47). The feast creates reformers who cannot tolerate idolatry in their midst.</p>",
    "2": "<p>Hezekiah reorganizes the priests and Levites by their divisions for burnt offerings, fellowship offerings, ministry, thanksgiving, and praise at the gates. The comprehensive organizational framework — each person with a specific assigned role — is the re-implementation of David&rsquo;s vision (1 Chr 23-26). Christ similarly organizes his body for ministry: &ldquo;it was he who gave some to be apostles, some to be prophets, some to be evangelists, and some to be pastors and teachers, to equip his people for works of service&rdquo; (Eph 4:11-12).</p>",
    "3": "<p>The king contributes from his own possessions for the burnt offerings: morning and evening offerings, Sabbath offerings, new moon offerings, appointed feast offerings — the full liturgical calendar. The king who funds the daily worship from his own resources is the model of the one who &ldquo;though he was rich, yet for your sake he became poor, so that you through his poverty might become rich&rdquo; (2 Cor 8:9). The royal provision sustains worship that the people could not sustain independently.</p>",
    "4": "<p>Hezekiah commands the people of Jerusalem to give the portion due to the priests and Levites &ldquo;so that they could devote themselves to the law of the LORD.&rdquo; The economic support of those who teach the Torah enables full-time ministry of the word — the same principle Paul articulates: &ldquo;the Lord has commanded that those who preach the gospel should receive their living from the gospel&rdquo; (1 Cor 9:14); &ldquo;the worker deserves his wages&rdquo; (1 Tim 5:18). The tithe system is the economic enablement of full-time covenant teaching.</p>",
    "5": "<p>As soon as the command goes out, the Israelites bring abundance: firstfruits of grain, wine, oil, honey, and all the produce — and &ldquo;they brought a great tithe of everything.&rdquo; The abundance of the people&rsquo;s giving in response to the restored covenant parallels the early church&rsquo;s generosity: &ldquo;all the believers were one in heart and mind. No one claimed that any of their possessions was their own, but they shared everything they had&rdquo; (Acts 4:32). The covenant renewal produces economic transformation as a direct consequence.</p>",
    "6": "<p>The people of Israel and Judah bring the tithe of cattle and sheep and the tithe of the holy things consecrated to the LORD their God — placing them in heaps (<em>ʿᵃrēmôṯ</em>). The agricultural and livestock tithes alongside the dedicated offerings represent the total sanctification of economic life: all categories of produce belong to YHWH. The NT vision of complete consecration: &ldquo;offer your bodies as a living sacrifice, holy and pleasing to God — this is your true and proper worship&rdquo; (Rom 12:1).</p>",
    "7": "<p>They begin piling up the heaps in the third month (Sivan — the month of Shavuot/Pentecost, when the firstfruits of wheat are gathered) and finish in the seventh month (Tishri — the month of the harvest feast). The tithe collection spans the entire harvest calendar from Pentecost to Tabernacles. The third month is also the month of the giving of the Torah at Sinai (Exod 19:1), so the tithing that begins in the third month is an act of Torah obedience aligned with the Sinai covenant.</p>",
    "8": "<p>When Hezekiah and the officials see the heaps, they bless the LORD and his people Israel. The king&rsquo;s blessing of the people in response to their faithfulness is the covenant reciprocity structure: the king blesses those who are faithful to the covenant obligations. This is the reverse of the punitive king; the blessing king is the type of Christ who will say &ldquo;come, you who are blessed by my Father; take your inheritance, the kingdom prepared for you since the creation of the world&rdquo; (Matt 25:34) — the blessing spoken over those who lived faithfully.</p>",
    "9": "<p>Hezekiah questions the priests and Levites about the heaps — the king takes an interest in the management of the temple stores, ensuring accountability and proper use. The oversight of the king over the temple&rsquo;s economic system reflects the Chronicler&rsquo;s vision of royal stewardship: the king is responsible not only for worship but for its material sustainability. Christ exercises the same oversight of his house: the letters to the seven churches in Rev 2-3 address both worship and economic practice.</p>",
    "10": "<p>Azariah the chief priest of Zadok&rsquo;s house reports: &ldquo;Since the people began bringing offerings to the LORD&rsquo;s house, we have had enough to eat and plenty to spare (<em>wᵉhôtēr lārōb</em>), for the LORD has blessed his people, and this great amount is what is left.&rdquo; The abundance that remains after the Levites have eaten is the sign of divine blessing. This is the economic miracle of tithing: the more that is given, the more remains. Paul expresses the same principle: &ldquo;whoever sows generously will also reap generously... God is able to bless you abundantly, so that in all things at all times, having all that you need, you will abound in every good work&rdquo; (2 Cor 9:6, 8).</p>",
    "11": "<p>Hezekiah commands storage chambers prepared in the temple — the institutional infrastructure to manage the surplus. The surplus of generosity requires organizational capacity to steward it; the reform produces more than the existing systems can handle without expansion. The church faces the same creative problem: the abundance of gifts given to the apostles requires the appointment of the seven (Acts 6:1-7) to manage distribution justly.</p>",
    "12": "<p>They faithfully bring in the contributions, tithes, and dedicated things — Cononiah the Levite in charge with Shimei his brother as second. The appointment of specific named leaders for financial stewardship reflects the principle of accountability in the management of covenant resources. Paul emphasizes the same principle: &ldquo;we are taking pains to do what is right, not only in the eyes of the Lord but also in the eyes of man&rdquo; (2 Cor 8:21) — financial stewardship in the covenant community must be transparent and above reproach.</p>",
    "13": "<p>Ten named overseers serve under Cononiah — a full administrative team for the tithe system. The detailed personnel list for financial administration reflects the Chronicler&rsquo;s characteristic concern for organizational completeness and individual accountability. In the governance of Christ&rsquo;s body, specific individuals are appointed and named (Acts 6:5 names the seven) rather than anonymous bureaucracy — persons, not structures, bear responsibility.</p>",
    "14": "<p>Kore son of Imnah the Levite, keeper of the East Gate, is in charge of distributing freewill offerings and the most holy things. The East Gate keeper distributing holy things is a significant detail: the east gate faces the sunrise, the direction of approach (and of YHWH&rsquo;s glory in Ezek 43:2); the freewill offering (<em>nᵉḏāḇāh</em>) is the offering given voluntarily, not under compulsion — the highest form of giving. The keeper of the eastern dawn-gate distributing freewill gifts is the type of Christ who opens the way to the Father&rsquo;s presence and who distributes the gifts of the Spirit freely (Eph 4:8: &ldquo;when he ascended on high, he took many captives and gave gifts to his people&rdquo;).</p>",
    "15": "<p>Eden, Miniamin, Jeshua, Shemaiah, Amariah, and Shecaniah faithfully distribute in the priestly cities to their brothers — every category included, from the youngest to the oldest. The distribution reaches to every class: great and small, young and old. The NT eucharistic distribution follows the same inclusive principle: the bread and cup are given to all without regard to status (1 Cor 11:20-22 rebukes those who create hierarchies at the Lord&rsquo;s table).</p>",
    "16": "<p>Daily portions are given to every male from three years old and upward who enters the temple by division — the youngest who can participate in temple service receives his portion. The inclusion of children (from age 3) in the distribution of priestly provision reflects the covenant community&rsquo;s care for the youngest members. Jesus makes children paradigmatic members of the kingdom: &ldquo;let the little children come to me... for the kingdom of heaven belongs to such as these&rdquo; (Matt 19:14).</p>",
    "17": "<p>The priests enrolled by their ancestral families, Levites from twenty years and upward by their divisions — the genealogical structure of the covenant community ensures that everyone belongs within a known network of family and function. The covenant community is not an assembly of isolated individuals but a family of families, each person located within a specific genealogical and functional structure. Christ calls his people into this same family structure: &ldquo;you are no longer foreigners and strangers, but fellow citizens with God&rsquo;s people and also members of his household&rdquo; (Eph 2:19).</p>",
    "18": "<p>The genealogy includes all their little children, their wives, their sons and daughters — the whole assembly consecrates itself to holiness. The family structure of the Levitical enrollment encompasses everyone in the household, not merely the cultic functionaries. The covenant community is not a fellowship of specialists but a family that includes every dependent. The NT equivalent: &ldquo;the promise is for you and your children and for all who are far off&rdquo; (Acts 2:39).</p>",
    "19": "<p>For the sons of Aaron who live in the common pasturelands of their cities, designated men are appointed to give portions to every male among the priests and to everyone enrolled by genealogy among the Levites. The distribution system reaches even to those who live outside Jerusalem — the priests in the outlying towns receive their portions through appointed distributors. The pastoral care of the covenant community extends to the geographically distant; Christ&rsquo;s body similarly reaches the scattered: &ldquo;I have other sheep that are not of this fold; I must bring them also&rdquo; (John 10:16).</p>",
    "20": "<p>&ldquo;Thus Hezekiah acted throughout all Judah, doing what was good (<em>ṭôḇ</em>) and right (<em>yāšār</em>) and faithful (<em>ʾĕmeṯ</em>) before the LORD his God.&rdquo; The threefold summary — good, right, faithful — is the Chronicler&rsquo;s highest commendation for a king&rsquo;s comprehensive reign. Hezekiah&rsquo;s summary encompasses the temple cleansing (ch 29), the Passover (ch 30), and the reform (ch 31); it covers worship, feast, and economics. The triad <em>ṭôḇ / yāšār / ʾĕmeṯ</em> (good, straight/right, truth/faithfulness) maps onto the NT description of Christ&rsquo;s character: &ldquo;I am the way and the truth and the life&rdquo; (John 14:6) — the embodiment of all three qualities.</p>",
    "21": "<p>&ldquo;In every work he undertook in the service of the house of God, in the law, and in the commandments, seeking his God with all his heart (<em>bᵉḵol-lᵉḇāḇô</em>), he prospered.&rdquo; The whole-heart summary closes the section: Hezekiah is the king who met the Deuteronomic ideal (Deut 6:5: &ldquo;love the LORD your God with all your heart&rdquo;). His prosperity is covenantally grounded in the whole-hearted seeking that the law commanded. Jesus is the one who not merely sought God with a whole heart but fulfilled the Shema perfectly (&ldquo;You shall love the Lord your God with all your heart and with all your soul and with all your mind,&rdquo; Matt 22:37) — and in doing so, fulfills the law that Hezekiah only partially achieved (Matt 5:17: &ldquo;I have not come to abolish the Law but to fulfill it&rdquo;).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '2chronicles')
    merge_comm(existing, CHRON2_CHRIST_29_31)
    save_comm('mkt-christ', '2chronicles', existing)
    print('2 Chronicles 29-31 christ layer written.')

if __name__ == '__main__':
    main()
